import{_ as a,o as r,c as i,S as e}from"./chunks/framework.C6RQlTYc.js";const b=JSON.parse('{"title":"模型量化","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_16-quantization.md","filePath":"直击概念/17ai/s_ai_16-quantization.md","lastUpdated":1778207238000}'),n={name:"直击概念/17ai/s_ai_16-quantization.md"};function o(l,t,d,h,s,u){return r(),i("div",null,[...t[0]||(t[0]=[e('<h1 id="模型量化" tabindex="-1">模型量化 <a class="header-anchor" href="#模型量化" aria-label="Permalink to &quot;模型量化&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>模型量化（Quantization）是将神经网络的<strong>参数从高精度（如 32 位浮点数）转换为低精度（如 4 位/8 位整数）</strong>，以降低模型体积和推理显存需求的技术。本质是用精度换效率。</p><p>类比：一张 24-bit 的 BMP 图片转为 8-bit PNG，肉眼几乎看不出区别但体积大幅减小。</p><h2 id="为什么要量化" tabindex="-1">为什么要量化 <a class="header-anchor" href="#为什么要量化" aria-label="Permalink to &quot;为什么要量化&quot;">​</a></h2><p>LLM 部署面临的主要挑战：</p><table><thead><tr><th>模型规模</th><th>FP32 显存</th><th>量化后 (INT4)</th></tr></thead><tbody><tr><td>Llama 3 8B</td><td>~32 GB</td><td>~5 GB</td></tr><tr><td>Llama 3 70B</td><td>~280 GB</td><td>~40 GB</td></tr><tr><td>DeepSeek V3 671B</td><td>~2.6 TB</td><td>~350 GB (INT4)</td></tr></tbody></table><p>量化使得在<strong>消费级硬件</strong>（甚至浏览器中）运行大模型成为可能。</p><h2 id="量化精度对比" tabindex="-1">量化精度对比 <a class="header-anchor" href="#量化精度对比" aria-label="Permalink to &quot;量化精度对比&quot;">​</a></h2><table><thead><tr><th>精度</th><th>位数</th><th>常见应用</th></tr></thead><tbody><tr><td>FP32</td><td>32</td><td>原始训练精度</td></tr><tr><td>FP16/BF16</td><td>16</td><td>主流推理精度</td></tr><tr><td>INT8</td><td>8</td><td>边缘端推理</td></tr><tr><td>INT4</td><td>4</td><td>消费级 GPU 推理</td></tr><tr><td>INT2/NiB</td><td>2-3</td><td>极端压缩</td></tr></tbody></table><h2 id="量化方法" tabindex="-1">量化方法 <a class="header-anchor" href="#量化方法" aria-label="Permalink to &quot;量化方法&quot;">​</a></h2><h3 id="训练后量化-ptq-post-training-quantization" tabindex="-1">训练后量化（PTQ - Post-Training Quantization） <a class="header-anchor" href="#训练后量化-ptq-post-training-quantization" aria-label="Permalink to &quot;训练后量化（PTQ - Post-Training Quantization）&quot;">​</a></h3><p>模型训练完成后直接量化，不需要重新训练：</p><ul><li><strong>优点</strong>：快速、简单</li><li><strong>缺点</strong>：精度损失较大，尤其是 4-bit 以下</li></ul><h3 id="量化感知训练-qat-quantization-aware-training" tabindex="-1">量化感知训练（QAT - Quantization-Aware Training） <a class="header-anchor" href="#量化感知训练-qat-quantization-aware-training" aria-label="Permalink to &quot;量化感知训练（QAT - Quantization-Aware Training）&quot;">​</a></h3><p>在训练时就模拟量化效果，让模型&quot;适应&quot;低精度：</p><ul><li><strong>优点</strong>：精度损失小</li><li><strong>缺点</strong>：需要重新训练，成本高</li></ul><h3 id="gguf-gptq" tabindex="-1">GGUF / GPTQ <a class="header-anchor" href="#gguf-gptq" aria-label="Permalink to &quot;GGUF / GPTQ&quot;">​</a></h3><p>两种最主流的 PTQ 格式：</p><ul><li><strong>GGUF</strong>（GGML Universal Format）：llama.cpp 使用的格式，支持 CPU 推理，生态丰富</li><li><strong>GPTQ</strong>：针对 GPU 量化优化，通常精度损失更小</li><li><strong>AWQ</strong>（Activation-aware Weight Quantization）：新一代方法，精度优于 GPTQ</li></ul><h2 id="前端相关" tabindex="-1">前端相关 <a class="header-anchor" href="#前端相关" aria-label="Permalink to &quot;前端相关&quot;">​</a></h2><ul><li><strong>WebLLM</strong>：基于 WebGPU 在浏览器中运行量化模型（如 Llama 3 INT4）</li><li><strong>Transformers.js</strong>：Hugging Face 的浏览器推理库</li><li><strong>ONNX Runtime Web</strong>：支持 WebGL/WebGPU 的量化模型推理</li></ul><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>模型量化的核心思想是什么？为什么能大幅减小体积？</li><li>FP16、INT8、INT4 分别适用于什么场景？</li><li>你了解哪些在浏览器中运行 LLM 的方案？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://github.com/ggerganov/llama.cpp" target="_blank" rel="noreferrer">GGUF and llama.cpp</a></li><li><a href="https://arxiv.org/abs/2306.00978" target="_blank" rel="noreferrer">AWQ: Activation-aware Weight Quantization</a></li></ul>',26)])])}const c=a(n,[["render",o]]);export{b as __pageData,c as default};
